class Solution:
    def minSwapsCouples(self, row: List[int]) -> int:
        n = len(row) // 2
        pos = {x: i for i, x in enumerate(row)}
        swaps = 0
        for i in range(0, len(row), 2):
            j = row[i] ^ 1
            if row[i + 1] != j:
                swaps += 1
                k = pos[j]
                pos[row[i + 1]] = k
                row[k] = row[i + 1]
                row[i + 1] = j
        return swaps
